import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { createSignal } from 'decantr/state';
import { Card, Badge, Button, icon } from 'decantr/components';

code.example:
function AnatomyViewer({ pattern }) {
  const { div, h3, span, code, ul, li } = tags;
  const [selected, setSelected] = createSignal(null);

  return div({ class: css('_grid _gc1 _lg:gc2 _gap6') },
    // Left: Preview with hotspots
    Card({ class: css('_relative _overflow[hidden]') },
      div({ class: css('_bgmuted/10 _p6 _flex _center _minh[300px]') },
        // Pattern preview rendered here with numbered overlays
        span({ class: css('_fgmuted') }, 'Pattern Preview')
      )
    ),
    // Right: Breakdown panel
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Components')),
      Card.Body({},
        ul({ class: css('_flex _col _gap2') },
          ...pattern.components.map((c, i) =>
            li({ 
              class: css('_flex _aic _gap2 _p2 _r1 _cursor[pointer] _h:bgmuted/10'),
              onclick: () => setSelected(c)
            },
              Badge({ variant: 'outline', size: 'sm' }, String(i + 1)),
              span({ class: css('_textsm') }, c)
            )
          )
        )
      )
    )
  );
}

